// Computes the HMAC signature header pair expected by the backend
// VideoOpsCallbackAuthService for POST /api/video-ops/workflow-runs/:id/complete.
//
// Inputs ($json):
//   - workflowRunId    : long
//   - body             : object — the JSON body that will be POSTed verbatim
//   - method           : string — defaults to 'POST'
//   - path             : string — defaults to '/api/video-ops/workflow-runs/<id>/complete'
//
// Output:
//   - timestamp, signature : the X-Workflow-Timestamp and X-Workflow-Signature
//                            headers to attach to the outgoing HTTP request.
//
// The HMAC secret is read from $env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_HMAC_SECRET
// to keep the secret out of every parent workflow.

const crypto = require('crypto');

const secret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_HMAC_SECRET || '');
if (!secret) {
  throw new Error('APP_VIDEO_OPS_WORKFLOW_CALLBACK_HMAC_SECRET env var is empty.');
}

const workflowRunId = Number($json.workflowRunId || 0);
if (!workflowRunId || workflowRunId <= 0) {
  throw new Error('workflowRunId is required and must be > 0.');
}

const method = String($json.method || 'POST').toUpperCase();
const path = String($json.path || ('/api/video-ops/workflow-runs/' + workflowRunId + '/complete'));
const bodyObj = $json.body && typeof $json.body === 'object' ? $json.body : {};
const bodyJson = JSON.stringify(bodyObj);

const timestamp = String(Math.floor(Date.now() / 1000));
const payload = method + '\n' + path + '\n' + timestamp + '\n' + bodyJson;
const signature = crypto
  .createHmac('sha256', secret)
  .update(payload, 'utf8')
  .digest('hex');

return [{
  json: {
    timestamp,
    signature,
    method,
    path,
    body: bodyObj,
    bodyJson,
  },
}];
